struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& adaptor) const {
        adaptor(packet_id, username);
        adaptor & hexi::prefixed(scores);
        adaptor & hexi::null_terminated(metadata);
    }
};

