```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a hexi::file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer was successfully opened using the boolean conversion operator
    if (!buffer) {
        return {}; // Return empty vector on failure
    }

    // Create a destination vector with the required header size
    std::vector<uint8_t> destination(header_size);

    // Use the peek method to copy header data without advancing the read pointer
    buffer.peek(destination.data(), header_size);

    // Return the destination vector containing the header data
    return destination;
}
```

