#include <hexi/file_buffer.h>
#include <cstdint>
#include <filesystem>

int32_t read_int32_from_file(const std::filesystem::path& file_path) {
    // Create a hexi::file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state
    if (!buffer) {
        return 0; // Return default value if file cannot be opened or is invalid
    }

    // Use the read method to read the int32_t value from the file buffer
    int32_t value;
    buffer.read(value);

    // Return the read value
    return value;
}

float read_float_from_file(const std::filesystem::path& file_path) {
    // Create a hexi::file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state
    if (!buffer) {
        return 0.0f; // Return default value if file cannot be opened or is invalid
    }

    // Use the read method to read the float value from the file buffer
    float value;
    buffer.read(value);

    // Return the read value
    return value;
}
```

