#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create a buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    std::size_t total_written = 0;

    // Iterate through each chunk and write to the buffer
    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t available_space = adaptor.free();

        // If chunk is larger than available space, break to avoid overflow
        if (available_space < chunk.size()) {
            break;
        }

        // Write the chunk data
        adaptor.write(chunk.data(), chunk.size());

        // Update total written size
        total_written += chunk.size();
    }

    // Return the total size written
    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read (minimum of chunk_size or remaining data)
        std::size_t read_amount = std::min(adaptor.size(), chunk_size);

        // Create temporary buffer for reading
        std::vector<uint8_t> temp_buffer(read_amount);

        // Read data from the adaptor
        adaptor.read(temp_buffer.data(), read_amount);

        // Append to result
        result.insert(result.end(), temp_buffer.begin(), temp_buffer.end());
